const body = ($json.content && $json.content[0] && $json.content[0].text) ? $json.content[0].text : '';
const subject = "Your calculator range. The part it can't show.";
const preheader = "What most homeowners learn about impact pricing too late.";
const paras = body.split(/\n\n+/).map(p => '<p style="margin:0 0 16px;font-size:16px;line-height:1.6;color:#1f2d3d;">' + p.replace(/\n/g,'<br>') + '</p>').join('');
const loc  = "{{" + "location.name" + "}}";
const addr = "{{" + "location.full_address" + "}}";
const unsub= "{{" + "email.unsubscribe_link" + "}}";
const html =
'<!--' + preheader + '--><div style="display:none;max-height:0;overflow:hidden;opacity:0;">' + preheader + '</div>' +
'<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f4f6f8;padding:24px 0;font-family:Arial,Helvetica,sans-serif;"><tr><td align="center">' +
'<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:6px;overflow:hidden;">' +
'<tr><td style="background:#122739;padding:20px 28px;"><span style="color:#ffffff;font-size:18px;font-weight:bold;letter-spacing:.5px;">Reece Windows &amp; Doors</span></td></tr>' +
'<tr><td style="padding:28px 28px 8px;">' + paras + '</td></tr>' +
'<tr><td style="padding:0 28px 24px;"><div style="border-top:1px solid #e2e8f0;padding-top:16px;font-size:13px;color:#5a6b7b;">Family-Owned Since 1972 &middot; Serving Florida Since 2005 &middot; Transferable double lifetime warranty on parts and labor</div></td></tr>' +
'<tr><td style="background:#f0f3f6;padding:18px 28px;font-size:12px;color:#8a99a8;line-height:1.5;">' + loc + '<br>' + addr + '<br><a href="' + unsub + '" style="color:#8a99a8;">Unsubscribe</a></td></tr>' +
'</table></td></tr></table>';
return [{ json: { emailBody: body, html, subject, preheader } }];

// Branch B — A/B arm + copy select. Tokens stay intact; GHL resolves {{contact.*}}/{{trigger_link.*}}/{{custom_values.*}}/{{right_now.*}} on the inline send. No resolution here.
const copy = {"A": ["Hi {{contact.first_name}}, it’s {{custom_values.rep_name}} from Reece Windows & Doors. Saw you started an estimate but didn’t finish - totally normal. Before you go back, one quick thing: there’s a factor in {{contact.city}} that can skew the price more than most people expect. This explains it: {{trigger_link.KomFFHfauq43DNaAeOnG}}", "{{contact.first_name}}, {{custom_values.rep_name}} again. Quick heads up - there’s a factor in {{contact.city}} that can swing window pricing more than people expect, sometimes lower. Worth finishing to see how yours shakes out: {{trigger_link.lNpY45389VjyMNnF2IUY}}", "{{contact.first_name}}, a homeowner in {{contact.city}} finished theirs last week and was surprised the number came in lower than the contractor they’d already talked to. That doesn’t always happen - but it does more often than people expect. Only way to know where yours lands: {{trigger_link.ERoRZriPkgtxPJH4jlqb}} \nI’ll leave it there for now."], "B": ["Hi {{contact.first_name}}, this is {{custom_values.rep_name}} at Reece. Most homeowners stop at the measurement step, nobody has window sizes sitting in their head. You don't actually have to finish it. We can come measure everything for you, free, and give you the accurate number based on your actual home.\n\nWant to go that route instead? {{trigger_link.qFFf2RCT3sSG80aUf0e3}}", "The home visit replaces the calculator - we measure everything, give you the accurate number, and you decide. No homework on your end.\n\nHere if you want:\n{{trigger_link.PMHam62lpHp9DLyl19Nj}}", "Last note from me, {{contact.first_name}}. Honestly, the home visit is usually faster than trying to estimate everything manually — and the number is more accurate because we can see things the calculator can't.\n\nIf counting and measuring windows isn't how you want to spend your {{right_now.day_of_week}}, this is the easier path:\n{{trigger_link.L7uHzOECQjATvoqwXkUl}}"]};
const contactId = String($('Normalize Input').first().json.contactId || '');
const abSplitRatioArmA = 0.5;
function frac(s){ let h=0; for (let i=0;i<s.length;i++){ h=(h*31 + s.charCodeAt(i)) >>> 0; } return (h % 10000)/10000; }
const arm = frac(contactId) < abSplitRatioArmA ? 'A' : 'B';
const armTag = arm === 'A' ? 'e2-ab-test:arm-a' : 'e2-ab-test:arm-b';
const b = copy[arm];
return [{ json: { arm, armTag, body1: b[0], body2: b[1], body3: b[2] } }];
